Add-Type -AssemblyName PresentationFramework
Add-Type -AssemblyName PresentationCore
Add-Type -AssemblyName WindowsBase
Add-Type -AssemblyName Microsoft.VisualBasic
Add-Type -AssemblyName System.Windows.Forms

$script:supportedExts = @('.jpg','.jpeg','.png','.bmp','.gif','.tiff','.tif','.ico')
$script:iniDir = [System.IO.Path]::Combine([Environment]::GetFolderPath('LocalApplicationData'), "PSPhotoViewer")
$script:iniPath = [System.IO.Path]::Combine($script:iniDir, "PhotoViewer.ini")

function Read-Ini {
    $d = @{ WindowWidth=1200; WindowHeight=720; WindowState="Normal"; WindowLeft=-1; WindowTop=-1
        LeftPanelWidth=280; PreviewListHeight=300; ThumbSize=64; LastFolder=""; ZoomMode="BestFit"
        ViewMode="Thumbnails"; LeftPanelVisible=1; DetailColName=200; DetailColSize=80; DetailColDate=140
        SortColumn="Name"; SortDirection="Ascending" }
    if (-not [System.IO.File]::Exists($script:iniPath)) {
        try { if (-not [System.IO.Directory]::Exists($script:iniDir)){[System.IO.Directory]::CreateDirectory($script:iniDir)|Out-Null}; Write-Ini $d } catch {}
        return $d
    }
    try {
        foreach ($line in [System.IO.File]::ReadAllLines($script:iniPath)) {
            $line=$line.Trim(); if($line.StartsWith('#') -or $line.StartsWith(';') -or -not $line.Contains('=')){continue}
            $parts=$line.Split('=',2); $key=$parts[0].Trim(); $val=$parts[1].Trim()
            if ($d.ContainsKey($key)) {
                if ($key -match 'Folder|ZoomMode|WindowState|ViewMode|SortColumn|SortDirection'){$d[$key]=$val}
                else{$p=0; if([int]::TryParse($val,[ref]$p)){$d[$key]=$p}}
            }
        }
    } catch {}
    return $d
}

function Write-Ini([hashtable]$cfg) {
    try {
        if(-not [System.IO.Directory]::Exists($script:iniDir)){[System.IO.Directory]::CreateDirectory($script:iniDir)|Out-Null}
        $lines=@("# PSPhotoViewer Configuration","")
        foreach($k in $cfg.Keys|Sort-Object){$lines+="$k=$($cfg[$k])"}
        [System.IO.File]::WriteAllLines($script:iniPath,$lines)
    } catch {}
}

function Save-CurrentConfig {
    if($window.WindowState -eq [System.Windows.WindowState]::Normal){
        $script:config.WindowWidth=[int]$window.ActualWidth; $script:config.WindowHeight=[int]$window.ActualHeight
        $script:config.WindowLeft=[int]$window.Left; $script:config.WindowTop=[int]$window.Top; $script:config.WindowState="Normal"
    } elseif($window.WindowState -eq [System.Windows.WindowState]::Maximized){
        $script:config.WindowState="Maximized"; $rb=$window.RestoreBounds
        if($rb.Width -gt 0){$script:config.WindowWidth=[int]$rb.Width; $script:config.WindowHeight=[int]$rb.Height; $script:config.WindowLeft=[int]$rb.Left; $script:config.WindowTop=[int]$rb.Top}
    }
    $script:config.LeftPanelWidth=$script:savedPanelWidth
    $script:config.PreviewListHeight=[int]$PreviewListBorder.Height
    $script:config.ThumbSize=$script:thumbSize; $script:config.ZoomMode=$script:zoomMode; $script:config.ViewMode=$script:viewMode
    $script:config.LeftPanelVisible=if($script:panelVisible){1}else{0}
    $script:config.DetailColName=[int]$DetailColNameDef.Width.Value; $script:config.DetailColSize=[int]$DetailColSizeDef.Width.Value; $script:config.DetailColDate=[int]$DetailColDateDef.Width.Value
    $script:config.SortColumn=$script:sortColumn; $script:config.SortDirection=$script:sortDirection
    if(-not [string]::IsNullOrEmpty($script:currentFolder)){$script:config.LastFolder=$script:currentFolder}
    Write-Ini $script:config
}

$script:config = Read-Ini

