"#FFAACCEE" Canvas.Left="5" Canvas.Top="10.5"/></Canvas></Button></StackPanel><TextBlock x:Name="PreviewHeader" Text="IMAGES (0)" Foreground="#FF6A8AA8" FontSize="10" FontWeight="SemiBold" VerticalAlignment="Center"/></DockPanel></Border>
