r Property="HorizontalContentAlignment" Value="Stretch"/><Setter Property="Template"><Setter.Value><ControlTemplate TargetType="ListBoxItem"><Border x:Name="bd" CornerRadius="3" Padding="4,2" Background="Transparent" BorderThickness="1" BorderBrush="Transparent"><ContentPresenter/></Border><ControlTemplate.Triggers><Trigger Property="IsMouseOver" Value="True"><Setter TargetName="bd" Property="Background" Value="#FF1E2E44"/><Setter TargetName="bd" Property="BorderBrush" Value="#FF3A5A78"/></Trigger><Trigger Property="IsSelected" Value="True"><Setter TargetName="bd" Property="Background" Value="#FF1A3A5A"/><Setter TargetName="bd" Property="BorderBrush" Value="#FF4A7AAA"/></Trigger></ControlTemplate.Triggers></ControlTemplate></Setter.Value></Setter></Style></ListBox.ItemContainerStyle></ListBox></DockPanel></Border>
          <Border DockPanel.Dock="Bottom" Height="6" Background="#FF10151C" Cursor="SizeNS" x:Name="PanelSplitHandle"><Border Height="2" Background="#FF2A3A4A" CornerRadius="1" VerticalAlignment="Center" Margin="20,0,20,0"/></Border>
