    <Border x:Name="FullScreenOverlay" Visibility="Collapsed" Background="Black" Focusable="True" Panel.ZIndex="200"><Grid><Image x:Name="FSImage" Stretch="Uniform" HorizontalAlignment="Center" VerticalAlignment="Center" RenderOptions.BitmapScalingMode="HighQuality"/><Border x:Name="FSBottomBar" VerticalAlignment="Bottom" HorizontalAlignment="Center" Margin="0,0,0,24" Background="#BB000000" CornerRadius="6" Padding="16,7"><StackPanel Orientation="Horizontal"><Button x:Name="FSPrevBtn" Background="Transparent" BorderThickness="0" Cursor="Hand" Width="38" Height="34" Margin="0,0,6,0"><Path Fill="White" Data="M 16,4 L 4,18 L 16,32 Z" Stretch="Uniform" Margin="10,6"/></Button><Button x:Name="FSPauseBtn" Background="Transparent" BorderThickness="0" Cursor="Hand" Width="38" Height="34" Margin="0,0,6,0"><Canvas Width="20" Height="20"><Rectangle Width="5" Height="16" Fill="White" Canvas.Left="2" Canvas.Top="2"/><Rectangle Width="5" Height="16" Fill="White" Canvas.Left="13" Canvas.Top="2"/></Canvas></Button><Button x:Name="FSExitBtn" Background="Transparent" BorderThickness="0" Cursor="Hand" Width="38" Height="34" Margin="0,0,6,0"><Path Stroke="White" StrokeThickness="2.5" StrokeStartLineCap="Round" StrokeEndLineCap="Round" Data="M 4,4 L 16,16 M 16,4 L 4,16" Stretch="Uniform" Margin="10,10"/></Button><Button x:Name="FSNextBtn" Background="Transparent" BorderThickness="0" Cursor="Hand" Width="38" Height="34"><Path Fill="White" Data="M 4,4 L 16,18 L 4,32 Z" Stretch="Uniform" Margin="10,6"/></Button></StackPanel></Border><Border x:Name="FSCountLabelBorder" Background="#88000000" CornerRadius="3" HorizontalAlignment="Right" VerticalAlignment="Top" Margin="0,12,18,0" Padding="4,2"><TextBlock x:Name="FSCountLabel" Text="" Foreground="White" FontSize="13"/></Border></Grid></Border>
  </Grid>
</Window>
"@

try{$reader=[System.Xml.XmlReader]::Create([System.IO.StringReader]::new($xamlString));$window=[System.Windows.Markup.XamlReader]::Load($reader)}catch{Write-Host "XAML FAILED: $($_.Exception.Message)" -ForegroundColor Red;exit}

$window.Width=$script:config.WindowWidth;$window.Height=$script:config.WindowHeight
if($script:config.WindowLeft -ge 0 -and $script:config.WindowTop -ge 0){$window.WindowStartupLocation=[System.Windows.WindowStartupLocation]::Manual;$window.Left=$script:config.WindowLeft;$window.Top=$script:config.WindowTop}
if($script:config.WindowState -eq "Maximized"){$window.WindowState=[System.Windows.WindowState]::Maximized}

# Element refs
$MainImage=$window.FindName("MainImage");$FSImage=$window.FindName("FSImage");$Overlay=$window.FindName("FullScreenOverlay");$Viewer=$window.FindName("Viewer");$ImageScale=$window.FindName("ImageScale")
$PlaceholderPanel=$window.FindName("PlaceholderPanel");$PlaceholderOpenBtn=$window.FindName("PlaceholderOpenBtn");$FileInfoLabel=$window.FindName("FileInfoLabel");$FileCountLabel=$window.FindName("FileCountLabel");$FileNameLabel=$window.FindName("FileNameLabel")
$FSBottomBar=$window.FindName("FSBottomBar");$FSCountLabelBorder=$window.FindName("FSCountLabelBorder");$FSCountLabel=$window.FindName("FSCountLabel")
$ZoomInBtn=$window.FindName("ZoomInBtn");$ZoomOutBtn=$window.FindName("ZoomOutBtn");$FitBtn=$window.FindName("FitBtn");$FSBtn=$window.FindName("FSBtn");$NextBtn=$window.FindName("NextBtn");$PrevBtn=$window.FindName("PrevBtn")
$FSNextBtn=$window.FindName("FSNextBtn");$FSPrevBtn=$window.FindName("FSPrevBtn");$FSPauseBtn=$window.FindName("FSPauseBtn");$FSExitBtn=$window.FindName("FSExitBtn");$DeleteBtn=$window.FindName("DeleteBtn")
$MenuOpen=$window.FindName("MenuOpen");$MenuFit=$window.FindName("MenuFit");$MenuActual=$window.FindName("MenuActual")
$OpenFolderBtn=$window.FindName("OpenFolderBtn");$FolderTree=$window.FindName("FolderTree");$FolderTreeHeader=$window.FindName("FolderTreeHeader")
$ImagePreviewList=$window.FindName("ImagePreviewList");$PreviewHeader=$window.FindName("PreviewHeader");$LeftPanelColumn=$window.FindName("LeftPanelColumn")
$ThumbSmallerBtn=$window.FindName("ThumbSmallerBtn");$ThumbLargerBtn=$window.FindName("ThumbLargerBtn");$ThumbSizeLabel=$window.FindName("ThumbSizeLabel");$ThumbSizePanel=$window.FindName("ThumbSizePanel")
$PreviewListBorder=$window.FindName("PreviewListBorder");$PanelSplitHandle=$window.FindName("PanelSplitHandle")
$ViewThumbBtn=$window.FindName("ViewThumbBtn");$ViewDetailBtn=$window.FindName("ViewDetailBtn");$HamburgerBtn=$window.FindName("HamburgerBtn");$LeftPanel=$window.FindName("LeftPanel");$MainSplitter=$window.FindName("MainSplitter")
$DetailHeaderRow=$window.FindName("DetailHeaderRow");$SortNameBtn=$window.FindName("SortNameBtn");$SortSizeBtn=$window.FindName("SortSizeBtn");$SortDateBtn=$window.FindName("SortDateBtn")
$SortNameText=$window.FindName("SortNameText");$SortSizeText=$window.FindName("SortSizeText");$SortDateText=$window.FindName("SortDateText")
$DetailColNameDef=$window.FindName("DetailColNameDef");$DetailColSizeDef=$window.FindName("DetailColSizeDef");$DetailColDateDef=$window.FindName("DetailColDateDef")

# Apply INI
$LeftPanelColumn.Width=[System.Windows.GridLength]::new($script:config.LeftPanelWidth,[System.Windows.GridUnitType]::Pixel)
$PreviewListBorder.Height=$script:config.PreviewListHeight
$DetailColNameDef.Width=[System.Windows.GridLength]::new($script:config.DetailColName,[System.Windows.GridUnitType]::Pixel)
$DetailColSizeDef.Width=[System.Windows.GridLength]::new($script:config.DetailColSize,[System.Windows.GridUnitType]::Pixel)
$DetailColDateDef.Width=[System.Windows.GridLength]::new($script:config.DetailColDate,[System.Windows.GridUnitType]::Pixel)

# State
$script:images=New-Object System.Collections.Generic.List[string];$script:imageCache=New-Object 'System.Collections.Generic.Dictionary[string,byte[]]'
$script:allFolderFiles=@();$script:currentIndex=0;$script:currentZoom=1.0;$script:fitZoom=1.0
$script:slideshowTimer=$null;$script:slideshowRunning=$false;$script:isDragging=$false;$script:dragStartPos=$null;$script:dragStartHOffset=0;$script:dragStartVOffset=0
$script:oldResizeMode='CanResize';$script:lastMousePos=$null;$script:currentFolder=$null;$script:updatingSelection=$false
$script:thumbSize=$script:config.ThumbSize;$script:thumbSizes=@(32,48,64,80,96,120,160,200)
$script:zoomMode=$script:config.ZoomMode;$script:viewMode=$script:config.ViewMode
$script:splitDragging=$false;$script:splitDragStartY=0;$script:splitDragStartH=0
$script:panelVisible=$script:config.LeftPanelVisible -ne 0
$script:savedPanelWidth=[int]$script:config.LeftPanelWidth
$script:sortColumn=$script:config.SortColumn;$script:sortDirection=$script:config.SortDirection
$script:maxPreviewLoad=200
$ThumbSizeLabel.Text="$($script:thumbSize)"

function Apply-PanelVisibility{
    if($script:panelVisible){$LeftPanel.Visibility='Visible';$MainSplitter.Visibility='Visible';$LeftPanelColumn.MinWidth=140;$LeftPanelColumn.Width=[System.Windows.GridLength]::new([Math]::Max($script:savedPanelWidth,140),[System.Windows.GridUnitType]::Pixel)}
    else{if($LeftPanelColumn.Width.Value -gt 10){$script:savedPanelWidth=[int]$LeftPanelColumn.Width.Value};$LeftPanel.Visibility='Collapsed';$MainSplitter.Visibility='Collapsed';$LeftPanelColumn.MinWidth=0;$LeftPanelColumn.Width=[System.Windows.GridLength]::new(0,[System.Windows.GridUnitType]::Pixel)}
    Save-CurrentConfig
}
Apply-PanelVisibility
function Apply-ViewMode{if($script:viewMode -eq "Details"){$DetailHeaderRow.Visibility='Visible';$ThumbSizePanel.Visibility='Collapsed'}else{$DetailHeaderRow.Visibility='Collapsed';$ThumbSizePanel.Visibility='Visible'}}
Apply-ViewMode
function Update-SortIndicators{$a=if($script:sortDirection -eq "Ascending"){" ▲"}else{" ▼"};$SortNameText.Text=if($script:sortColumn -eq "Name"){"Name$a"}else{"Name"};$SortSizeText.Text=if($script:sortColumn -eq "Size"){"Size$a"}else{"Size"};$SortDateText.Text=if($script:sortColumn -eq "Date"){"Date modified$a"}else{"Date modified"}}
Update-SortIndicators

# Timers
$script:fsIdleTimer=New-Object System.Windows.Threading.DispatcherTimer;$script:fsIdleTimer.Interval=[TimeSpan]::FromSeconds(5)
$script:fsIdleTimer.Add_Tick({if($Overlay.Visibility -eq 'Visible'){$window.Cursor=[System.Windows.Input.Cursors]::None;$FSBottomBar.Visibility='Collapsed';$FSCountLabelBorder.Visibility='Collapsed';$script:fsIdleTimer.Stop()}})
$Overlay.Add_MouseMove({param($s,$e);if($Overlay.Visibility -ne 'Visible'){return};$p=$e.GetPosition($Overlay);if($null -eq $script:lastMousePos){$script:lastMousePos=$p;return};if([Math]::Abs($p.X-$script:lastMousePos.X) -gt 2 -or [Math]::Abs($p.Y-$script:lastMousePos.Y) -gt 2){$script:lastMousePos=$p;if($window.Cursor -eq [System.Windows.Input.Cursors]::None){$window.Cursor=[System.Windows.Input.Cursors]::Arrow;$FSBottomBar.Visibility='Visible';$FSCountLabelBorder.Visibility='Visible'};$script:fsIdleTimer.Stop();$script:fsIdleTimer.Start()}})
$window.Add_StateChanged({if($window.WindowState -eq 'Minimized'){[System.GC]::Collect();[System.GC]::WaitForPendingFinalizers();[System.GC]::Collect()}})

# Deferred GC timer - runs once after idle
$script:gcTimer = New-Object System.Windows.Threading.DispatcherTimer
$script:gcTimer.Interval = [TimeSpan]::FromSeconds(3)
$script:gcTimer.Add_Tick({ $script:gcTimer.Stop(); [System.GC]::Collect(1, [System.GCCollectionMode]::Optimized) })
function Request-GC { $script:gcTimer.Stop(); $script:gcTimer.Start() }

# Split handle
$PanelSplitHandle.Add_MouseLeftButtonDown({param($s,$e);$script:splitDragging=$true;$script:splitDragStartY=($e.GetPosition($window)).Y;$script:splitDragStartH=$PreviewListBorder.Height;$PanelSplitHandle.CaptureMouse()|Out-Null;$e.Handled=$true})
$PanelSplitHandle.Add_MouseMove({param($s,$e);if(-not $script:splitDragging){return};$newH=$script:splitDragStartH+($script:splitDragStartY-($e.GetPosition($window)).Y);if($newH -lt 60){$newH=60};if($newH -gt 800){$newH=800};$PreviewListBorder.Height=$newH;$e.Handled=$true})
$PanelSplitHandle.Add_MouseLeftButtonUp({param($s,$e);if($script:splitDragging){$script:splitDragging=$false;$PanelSplitHandle.ReleaseMouseCapture();Save-CurrentConfig;$e.Handled=$true}})

# Track panel width from splitter drag
$MainSplitter.Add_DragCompleted({if($script:panelVisible -and $LeftPanelColumn.Width.Value -gt 10){$script:savedPanelWidth=[int]$LeftPanelColumn.Width.Value;Save-CurrentConfig}})

# Preview scroll - 8px per tick for very gentle scrolling
$PreviewListBorder.Add_PreviewMouseWheel({param($s,$e)
    $lb=$ImagePreviewList;if($null -eq $lb){return}
    try{$dec=[System.Windows.Media.VisualTreeHelper]::GetChild($lb,0);if($null -ne $dec){$sv=[System.Windows.Media.VisualTreeHelper]::GetChild($dec,0);if($null -ne $sv -and $sv -is [System.Windows.Controls.ScrollViewer]){if($e.Delta -gt 0){$sv.ScrollToVerticalOffset($sv.VerticalOffset-8)}else{$sv.ScrollToVerticalOffset($sv.VerticalOffset+8)};$e.Handled=$true}}}catch{}
})

# Helpers
function Format-FileSize([long]$b){if($b -ge 1MB){"{0:N1} MB" -f ($b/1MB)}elseif($b -ge 1KB){"{0:N0} KB" -f ($b/1KB)}else{"$b bytes"}}
function Get-FitZoom{if($null -eq $MainImage.Source){return 1.0};$iw=$MainImage.Source.PixelWidth;$ih=$MainImage.Source.PixelHeight;$vw=$Viewer.ActualWidth-16;$vh=$Viewer.ActualHeight-16;if($vw -le 0 -or $vh -le 0 -or $iw -le 0 -or $ih -le 0){return 1.0};$s=[Math]::Min($vw/$iw,$vh/$ih);if($s -gt 1.0){$s=1.0};return $s}
function Apply-Zoom([double]$z){if($z -lt 0.04){$z=0.04};if($z -gt 12.0){$z=12.0};$script:currentZoom=$z;$ImageScale.ScaleX=$z;$ImageScale.ScaleY=$z}
function Fit-ToWindow{$script:fitZoom=Get-FitZoom;Apply-Zoom $script:fitZoom}
function Apply-ZoomMode{if($script:zoomMode -eq "ActualSize"){Apply-Zoom 1.0}else{Fit-ToWindow}}

function Create-Thumbnail([string]$path,[int]$size=64){
    try{$stream=New-Object System.IO.FileStream($path,[System.IO.FileMode]::Open,[System.IO.FileAccess]::Read,[System.IO.FileShare]::ReadWrite,4096,[System.IO.FileOptions]::SequentialScan)
    try{$bmp=New-Object System.Windows.Media.Imaging.BitmapImage;$bmp.BeginInit();$bmp.CacheOption=[System.Windows.Media.Imaging.BitmapCacheOption]::OnLoad;$bmp.StreamSource=$stream;$bmp.DecodePixelWidth=$size;$bmp.EndInit();$bmp.Freeze();return $bmp}finally{$stream.Dispose()}}catch{return $null}
}

function New-PictureIcon{$c=New-Object System.Windows.Controls.Canvas;$c.Width=12;$c.Height=12;$c.Margin=[System.Windows.Thickness]::new(0,0,5,0);$f=New-Object System.Windows.Shapes.Rectangle;$f.Width=12;$f.Height=10;$f.RadiusX=1;$f.RadiusY=1;$f.Stroke=[System.Windows.Media.SolidColorBrush]::new([System.Windows.Media.ColorConverter]::ConvertFromString("#FF6A8AA8"));$f.StrokeThickness=1.2;$f.Fill=[System.Windows.Media.SolidColorBrush]::new([System.Windows.Media.ColorConverter]::ConvertFromString("#FF182838"));[System.Windows.Controls.Canvas]::SetTop($f,1);$c.Children.Add($f)|Out-Null;$su=New-Object System.Windows.Shapes.Ellipse;$su.Width=3;$su.Height=3;$su.Fill=[System.Windows.Media.SolidColorBrush]::new([System.Windows.Media.ColorConverter]::ConvertFromString("#FF88AACC"));[System.Windows.Controls.Canvas]::SetLeft($su,2);[System.Windows.Controls.Canvas]::SetTop($su,3);$c.Children.Add($su)|Out-Null;$m=New-Object System.Windows.Shapes.Path;$m.Fill=[System.Windows.Media.SolidColorBrush]::new([System.Windows.Media.ColorConverter]::ConvertFromString("#FF3A7A5A"));$m.Data=[System.Windows.Media.Geometry]::Parse("M 1,10 L 4,5 L 7,8 L 9,4 L 11,10 Z");$c.Children.Add($m)|Out-Null;return $c}

function New-PreviewElement-Thumbnails([string]$path,[int]$tp){
    $fi=[System.IO.FileInfo]::new($path);$thumb=Create-Thumbnail $path $tp;$sz=Format-FileSize $fi.Length
    $st=New-Object System.Windows.Controls.StackPanel;$st.Orientation=[System.Windows.Controls.Orientation]::Vertical;$st.HorizontalAlignment=[System.Windows.HorizontalAlignment]::Stretch
    $tb=New-Object System.Windows.Controls.Border;$tb.Width=$tp+4;$tb.Height=$tp+4;$tb.CornerRadius=[System.Windows.CornerRadius]::new(3);$tb.Background=[System.Windows.Media.SolidColorBrush]::new([System.Windows.Media.ColorConverter]::ConvertFromString("#FF0A0E14"));$tb.BorderBrush=[System.Windows.Media.SolidColorBrush]::new([System.Windows.Media.ColorConverter]::ConvertFromString("#FF2A3A4A"));$tb.BorderThickness=[System.Windows.Thickness]::new(1);$tb.HorizontalAlignment=[System.Windows.HorizontalAlignment]::Center
    $img=New-Object System.Windows.Controls.Image;$img.Source=$thumb;$img.Stretch=[System.Windows.Media.Stretch]::Uniform;$img.HorizontalAlignment=[System.Windows.HorizontalAlignment]::Center;$img.VerticalAlignment=[System.Windows.VerticalAlignment]::Center;$img.Margin=[System.Windows.Thickness]::new(2);[System.Windows.Media.RenderOptions]::SetBitmapScalingMode($img,[System.Windows.Media.BitmapScalingMode]::HighQuality);$tb.Child=$img;$st.Children.Add($tb)|Out-Null
    $nb=New-Object System.Windows.Controls.TextBlock;$nb.Text=$fi.Name;$nb.Foreground=[System.Windows.Media.SolidColorBrush]::new([System.Windows.Media.ColorConverter]::ConvertFromString("#FFBBCCDD"));$nb.FontSize=9;$nb.TextTrimming=[System.Windows.TextTrimming]::CharacterEllipsis;$nb.TextAlignment=[System.Windows.TextAlignment]::Center;$nb.HorizontalAlignment=[System.Windows.HorizontalAlignment]::Center;$nb.Margin=[System.Windows.Thickness]::new(2,3,2,0);$nb.ToolTip=$fi.Name;$nb.MaxWidth=$tp+20;$st.Children.Add($nb)|Out-Null
    $sb=New-Object System.Windows.Controls.TextBlock;$sb.Text=$sz;$sb.Foreground=[System.Windows.Media.SolidColorBrush]::new([System.Windows.Media.ColorConverter]::ConvertFromString("#FF5A7A98"));$sb.FontSize=8;$sb.TextAlignment=[System.Windows.TextAlignment]::Center;$sb.HorizontalAlignment=[System.Windows.HorizontalAlignment]::Center;$sb.Margin=[System.Windows.Thickness]::new(0,1,0,2);$st.Children.Add($sb)|Out-Null;return $st
}

function New-PreviewElement-Details([string]$path){
    $fi=[System.IO.FileInfo]::new($path);$szS=Format-FileSize $fi.Length;$dtS=$fi.LastWriteTime.ToString("g")
    $g=New-Object System.Windows.Controls.Grid;$g.Height=22
    $c0=New-Object System.Windows.Controls.ColumnDefinition;$c1=New-Object System.Windows.Controls.ColumnDefinition;$c2=New-Object System.Windows.Controls.ColumnDefinition;$c3=New-Object System.Windows.Controls.ColumnDefinition;$c4=New-Object System.Windows.Controls.ColumnDefinition
    $b0=New-Object System.Windows.Data.Binding("Width");$b0.Source=$DetailColNameDef;$b0.Mode=[System.Windows.Data.BindingMode]::OneWay;[System.Windows.Data.BindingOperations]::SetBinding($c0,[System.Windows.Controls.ColumnDefinition]::WidthProperty,$b0)|Out-Null
    $c1.Width=[System.Windows.GridLength]::new(3,[System.Windows.GridUnitType]::Pixel)
    $b2=New-Object System.Windows.Data.Binding("Width");$b2.Source=$DetailColSizeDef;$b2.Mode=[System.Windows.Data.BindingMode]::OneWay;[System.Windows.Data.BindingOperations]::SetBinding($c2,[System.Windows.Controls.ColumnDefinition]::WidthProperty,$b2)|Out-Null
    $c3.Width=[System.Windows.GridLength]::new(3,[System.Windows.GridUnitType]::Pixel)
