    $g.ColumnDefinitions.Add($c0);$g.ColumnDefinitions.Add($c1);$g.ColumnDefinitions.Add($c2);$g.ColumnDefinitions.Add($c3);$g.ColumnDefinitions.Add($c4)
    $np=New-Object System.Windows.Controls.StackPanel;$np.Orientation=[System.Windows.Controls.Orientation]::Horizontal;$np.VerticalAlignment=[System.Windows.VerticalAlignment]::Center;$np.Children.Add((New-PictureIcon))|Out-Null
    $nb=New-Object System.Windows.Controls.TextBlock;$nb.Text=$fi.Name;$nb.Foreground=[System.Windows.Media.SolidColorBrush]::new([System.Windows.Media.ColorConverter]::ConvertFromString("#FFBBCCDD"));$nb.FontSize=11;$nb.TextTrimming=[System.Windows.TextTrimming]::CharacterEllipsis;$nb.ToolTip=$fi.Name;$nb.VerticalAlignment=[System.Windows.VerticalAlignment]::Center;$np.Children.Add($nb)|Out-Null;[System.Windows.Controls.Grid]::SetColumn($np,0);$g.Children.Add($np)|Out-Null
    $sb=New-Object System.Windows.Controls.TextBlock;$sb.Text=$szS;$sb.Foreground=[System.Windows.Media.SolidColorBrush]::new([System.Windows.Media.ColorConverter]::ConvertFromString("#FF7A9AB8"));$sb.FontSize=10;$sb.VerticalAlignment=[System.Windows.VerticalAlignment]::Center;$sb.TextAlignment=[System.Windows.TextAlignment]::Right;$sb.Margin=[System.Windows.Thickness]::new(4,0,4,0);[System.Windows.Controls.Grid]::SetColumn($sb,2);$g.Children.Add($sb)|Out-Null
    $db=New-Object System.Windows.Controls.TextBlock;$db.Text=$dtS;$db.Foreground=[System.Windows.Media.SolidColorBrush]::new([System.Windows.Media.ColorConverter]::ConvertFromString("#FF5A7A98"));$db.FontSize=10;$db.VerticalAlignment=[System.Windows.VerticalAlignment]::Center;$db.Margin=[System.Windows.Thickness]::new(4,0,2,0);[System.Windows.Controls.Grid]::SetColumn($db,4);$g.Children.Add($db)|Out-Null;return $g
