function New-PreviewElement([string]$path,[int]$tp){if($script:viewMode -eq "Details"){New-PreviewElement-Details $path}else{New-PreviewElement-Thumbnails $path $tp}}

function Get-SortedFiles([string[]]$files){$infos=$files|ForEach-Object{[System.IO.FileInfo]::new($_)};switch($script:sortColumn){"Size"{$sorted=if($script:sortDirection -eq "Ascending"){$infos|Sort-Object Length}else{$infos|Sort-Object Length -Descending}}"Date"{$sorted=if($script:sortDirection -eq "Ascending"){$infos|Sort-Object LastWriteTime}else{$infos|Sort-Object LastWriteTime -Descending}}default{$sorted=if($script:sortDirection -eq "Ascending"){$infos|Sort-Object Name}else{$infos|Sort-Object Name -Descending}}};return @($sorted|ForEach-Object{$_.FullName})}

function Add-LoadMoreItem{$mb=New-Object System.Windows.Controls.TextBlock;$mb.Text="... $($script:images.Count-$script:batchMax) more - click to load all";$mb.Foreground=[System.Windows.Media.SolidColorBrush]::new([System.Windows.Media.ColorConverter]::ConvertFromString("#FF6A9AC0"));$mb.FontSize=11;$mb.TextAlignment=[System.Windows.TextAlignment]::Center;$mb.HorizontalAlignment=[System.Windows.HorizontalAlignment]::Center;$mb.Margin=[System.Windows.Thickness]::new(0,6,0,6);$mb.Cursor=[System.Windows.Input.Cursors]::Hand;$ImagePreviewList.Items.Add($mb)|Out-Null}

function Populate-ImagePreviews([string]$folderPath){
    $ImagePreviewList.Items.Clear();$script:images.Clear();$script:imageCache.Clear();$script:currentFolder=$folderPath
    $script:allFolderFiles=@([System.IO.Directory]::GetFiles($folderPath)|Where-Object{$script:supportedExts -contains [System.IO.Path]::GetExtension($_).ToLower()})
    $sortedAll=Get-SortedFiles $script:allFolderFiles;foreach($f in $sortedAll){$script:images.Add($f)}
    $PreviewHeader.Text="IMAGES ($($script:images.Count))";$fn=[System.IO.Path]::GetFileName($folderPath);if([string]::IsNullOrEmpty($fn)){$fn=$folderPath};$FolderTreeHeader.Text="FOLDERS - $fn"
    if($script:images.Count -eq 0){return}
    $script:batchIndex=0;$script:batchSize=10;$script:batchMax=[Math]::Min($script:images.Count,$script:maxPreviewLoad);$script:fileList=$script:images.ToArray()
    $script:batchAction=[System.Action]{$s=$script:batchIndex;$e=[Math]::Min($s+$script:batchSize,$script:batchMax);for($i=$s;$i -lt $e;$i++){$ImagePreviewList.Items.Add((New-PreviewElement $script:fileList[$i] $script:thumbSize))|Out-Null};$script:batchIndex=$e
        if($script:batchIndex -lt $script:batchMax){$window.Dispatcher.BeginInvoke([System.Windows.Threading.DispatcherPriority]::Background,$script:batchAction)|Out-Null}
        elseif($script:batchMax -lt $script:images.Count){Add-LoadMoreItem};Request-GC}
    $window.Dispatcher.BeginInvoke([System.Windows.Threading.DispatcherPriority]::Background,$script:batchAction)|Out-Null
}

function Load-MorePreviews{if($ImagePreviewList.Items.Count -gt 0){$l=$ImagePreviewList.Items[$ImagePreviewList.Items.Count-1];if($l -is [System.Windows.Controls.TextBlock]){$ImagePreviewList.Items.RemoveAt($ImagePreviewList.Items.Count-1)}};$sf=$script:batchMax;$script:batchMax=$script:images.Count;$script:batchIndex=$sf
    $script:batchAction=[System.Action]{$s=$script:batchIndex;$e=[Math]::Min($s+$script:batchSize,$script:batchMax);for($i=$s;$i -lt $e;$i++){$ImagePreviewList.Items.Add((New-PreviewElement $script:fileList[$i] $script:thumbSize))|Out-Null};$script:batchIndex=$e;if($script:batchIndex -lt $script:batchMax){$window.Dispatcher.BeginInvoke([System.Windows.Threading.DispatcherPriority]::Background,$script:batchAction)|Out-Null}else{Request-GC}}
    $window.Dispatcher.BeginInvoke([System.Windows.Threading.DispatcherPriority]::Background,$script:batchAction)|Out-Null}

function Rebuild-Previews{if($null -eq $script:currentFolder -or -not [System.IO.Directory]::Exists($script:currentFolder)){return};$sortedAll=Get-SortedFiles $script:allFolderFiles;$script:images.Clear();foreach($f in $sortedAll){$script:images.Add($f)};$ImagePreviewList.Items.Clear();if($script:images.Count -eq 0){return}
    $script:batchIndex=0;$script:batchSize=10;$script:batchMax=[Math]::Min($script:images.Count,$script:maxPreviewLoad);$script:fileList=$script:images.ToArray()
    $script:batchAction=[System.Action]{$s=$script:batchIndex;$e=[Math]::Min($s+$script:batchSize,$script:batchMax);for($i=$s;$i -lt $e;$i++){$ImagePreviewList.Items.Add((New-PreviewElement $script:fileList[$i] $script:thumbSize))|Out-Null};$script:batchIndex=$e
        if($script:batchIndex -lt $script:batchMax){$window.Dispatcher.BeginInvoke([System.Windows.Threading.DispatcherPriority]::Background,$script:batchAction)|Out-Null}
        else{if($script:batchMax -lt $script:images.Count){Add-LoadMoreItem};$script:updatingSelection=$true;if($ImagePreviewList.Items.Count -gt $script:currentIndex -and $script:currentIndex -ge 0){$ImagePreviewList.SelectedIndex=$script:currentIndex;$ImagePreviewList.ScrollIntoView($ImagePreviewList.SelectedItem)};$script:updatingSelection=$false;Request-GC}}
    $window.Dispatcher.BeginInvoke([System.Windows.Threading.DispatcherPriority]::Background,$script:batchAction)|Out-Null}

function Build-FolderTree([string]$rp){$FolderTree.Items.Clear();$ri=New-Object System.Windows.Controls.TreeViewItem;$rn=[System.IO.Path]::GetFileName($rp);if([string]::IsNullOrEmpty($rn)){$rn=$rp}
    $hp=New-Object System.Windows.Controls.StackPanel;$hp.Orientation=[System.Windows.Controls.Orientation]::Horizontal
    $ic=New-Object System.Windows.Controls.Canvas;$ic.Width=16;$ic.Height=14;$ic.Margin=[System.Windows.Thickness]::new(0,1,6,0);$fp=New-Object System.Windows.Shapes.Path;$fp.Fill=[System.Windows.Media.Brushes]::Goldenrod;$fp.Data=[System.Windows.Media.Geometry]::Parse("M 0,3 L 2,0 L 8,0 L 10,3 L 16,3 L 16,14 L 0,14 Z");$ic.Children.Add($fp)|Out-Null
    $lb=New-Object System.Windows.Controls.TextBlock;$lb.Text=$rn;$lb.Foreground=[System.Windows.Media.SolidColorBrush]::new([System.Windows.Media.ColorConverter]::ConvertFromString("#FFCCDDEE"));$lb.FontWeight=[System.Windows.FontWeights]::SemiBold
    $cnt=@([System.IO.Directory]::GetFiles($rp)|Where-Object{$script:supportedExts -contains [System.IO.Path]::GetExtension($_).ToLower()}).Count
    $hp.Children.Add($ic)|Out-Null;$hp.Children.Add($lb)|Out-Null
    if($cnt -gt 0){$cl=New-Object System.Windows.Controls.TextBlock;$cl.Text=" ($cnt)";$cl.Foreground=[System.Windows.Media.SolidColorBrush]::new([System.Windows.Media.ColorConverter]::ConvertFromString("#FF5A7A98"));$cl.FontSize=10;$hp.Children.Add($cl)|Out-Null}
    $ri.Header=$hp;$ri.Tag=$rp;$ri.IsExpanded=$true;Add-SubFolders $ri $rp 0 3;$FolderTree.Items.Add($ri)|Out-Null}

function Add-SubFolders($pi,$pp,$d,$mx){if($d -ge $mx){return};try{$dirs=[System.IO.Directory]::GetDirectories($pp)|Sort-Object}catch{return}
    foreach($dir in $dirs){$dn=[System.IO.Path]::GetFileName($dir);try{$at=[System.IO.File]::GetAttributes($dir);if($at -band [System.IO.FileAttributes]::Hidden){continue};if($at -band [System.IO.FileAttributes]::System){continue}}catch{continue}
        $si=New-Object System.Windows.Controls.TreeViewItem;$sp=New-Object System.Windows.Controls.StackPanel;$sp.Orientation=[System.Windows.Controls.Orientation]::Horizontal
        $ic2=New-Object System.Windows.Controls.Canvas;$ic2.Width=14;$ic2.Height=12;$ic2.Margin=[System.Windows.Thickness]::new(0,2,5,0);$fp2=New-Object System.Windows.Shapes.Path;$fp2.Fill=[System.Windows.Media.SolidColorBrush]::new([System.Windows.Media.ColorConverter]::ConvertFromString("#FF998844"));$fp2.Data=[System.Windows.Media.Geometry]::Parse("M 0,2.5 L 1.5,0 L 6,0 L 7.5,2.5 L 14,2.5 L 14,12 L 0,12 Z");$ic2.Children.Add($fp2)|Out-Null
        $lb2=New-Object System.Windows.Controls.TextBlock;$lb2.Text=$dn;$lb2.Foreground=[System.Windows.Media.SolidColorBrush]::new([System.Windows.Media.ColorConverter]::ConvertFromString("#FFAABBCC"));$sp.Children.Add($ic2)|Out-Null;$sp.Children.Add($lb2)|Out-Null
        try{$cnt=@([System.IO.Directory]::GetFiles($dir)|Where-Object{$script:supportedExts -contains [System.IO.Path]::GetExtension($_).ToLower()}).Count;if($cnt -gt 0){$cl=New-Object System.Windows.Controls.TextBlock;$cl.Text=" ($cnt)";$cl.Foreground=[System.Windows.Media.SolidColorBrush]::new([System.Windows.Media.ColorConverter]::ConvertFromString("#FF5A7A98"));$cl.FontSize=10;$sp.Children.Add($cl)|Out-Null}}catch{}
        $si.Header=$sp;$si.Tag=$dir;Add-SubFolders $si $dir ($d+1) $mx;$pi.Items.Add($si)|Out-Null}}

function Preload-Images{if($script:images.Count -le 1){return};$cp=$script:images[$script:currentIndex];$pi2=($script:currentIndex-1+$script:images.Count)%$script:images.Count;$ni=($script:currentIndex+1)%$script:images.Count;$pp=$script:images[$pi2];$np=$script:images[$ni];$kr=@();foreach($k in $script:imageCache.Keys){if($k -ne $cp -and $k -ne $pp -and $k -ne $np){$kr+=$k}};foreach($k in $kr){$script:imageCache.Remove($k)}
    $pa=[System.Action[string]]{param($pt);if($null -ne $script:imageCache -and -not $script:imageCache.ContainsKey($pt)){try{$script:imageCache[$pt]=[System.IO.File]::ReadAllBytes($pt)}catch{}}};foreach($p in @($np,$pp)){if(-not $script:imageCache.ContainsKey($p)){$window.Dispatcher.BeginInvoke([System.Windows.Threading.DispatcherPriority]::SystemIdle,$pa,$p)|Out-Null}}}

function Load-Image([string]$path){
    try{$bytes=$null;if($script:imageCache.ContainsKey($path)){$bytes=$script:imageCache[$path]}else{$bytes=[System.IO.File]::ReadAllBytes($path)}
    $stream=New-Object System.IO.MemoryStream(,$bytes);try{$bmp=New-Object System.Windows.Media.Imaging.BitmapImage;$bmp.BeginInit();$bmp.CacheOption=[System.Windows.Media.Imaging.BitmapCacheOption]::OnLoad;$bmp.StreamSource=$stream;$bmp.EndInit();$bmp.Freeze();return $bmp}finally{$stream.Dispose()}}catch{return $null}
}

function Update-Image{
    if($script:images.Count -eq 0){$PlaceholderPanel.Visibility='Visible';$MainImage.Source=$null;$FSImage.Source=$null;$FileInfoLabel.Text="";$FileCountLabel.Text="";$FileNameLabel.Text="";$window.Title="Windows Photo Viewer";return}
    $PlaceholderPanel.Visibility='Collapsed';$path=$script:images[$script:currentIndex];$bmp=Load-Image $path
    if($null -eq $bmp){$MainImage.Source=$null;$FSImage.Source=$null;$FileInfoLabel.Text="Error";$FileCountLabel.Text="$($script:currentIndex+1) of $($script:images.Count)";$FileNameLabel.Text="";$window.Title="Windows Photo Viewer";return}
    $MainImage.Source=$bmp;$FSImage.Source=$bmp;$window.Dispatcher.BeginInvoke([System.Windows.Threading.DispatcherPriority]::Loaded,[System.Action]{Apply-ZoomMode})|Out-Null
    $fi=[System.IO.FileInfo]::new($path);$FileNameLabel.Text=$fi.Name;$FileInfoLabel.Text="$($bmp.PixelWidth) x $($bmp.PixelHeight)  |  $(Format-FileSize $fi.Length)";$FileCountLabel.Text="$($script:currentIndex+1) of $($script:images.Count)";$FSCountLabel.Text="$($script:currentIndex+1) / $($script:images.Count)";$window.Title="$($fi.Name) - Windows Photo Viewer"
    $script:updatingSelection=$true;if($ImagePreviewList.Items.Count -gt $script:currentIndex){$ImagePreviewList.SelectedIndex=$script:currentIndex;$ImagePreviewList.ScrollIntoView($ImagePreviewList.SelectedItem)};$script:updatingSelection=$false
    Preload-Images;Request-GC
}

function Open-Folder{$fb=New-Object System.Windows.Forms.FolderBrowserDialog;$fb.Description="Select a folder";$fb.ShowNewFolderButton=$false;if(-not [string]::IsNullOrEmpty($script:config.LastFolder) -and [System.IO.Directory]::Exists($script:config.LastFolder)){$fb.SelectedPath=$script:config.LastFolder};if($fb.ShowDialog() -ne [System.Windows.Forms.DialogResult]::OK){return};if([string]::IsNullOrEmpty($fb.SelectedPath) -or -not [System.IO.Directory]::Exists($fb.SelectedPath)){return};Load-Folder $fb.SelectedPath}
function Load-Folder([string]$fp){$script:config.LastFolder=$fp;Build-FolderTree $fp;Populate-ImagePreviews $fp;if($script:images.Count -gt 0){$script:currentIndex=0;Update-Image}else{$PlaceholderPanel.Visibility='Visible';$MainImage.Source=$null;$FSImage.Source=$null;$FileInfoLabel.Text="";$FileCountLabel.Text="";$FileNameLabel.Text="";$window.Title="Windows Photo Viewer - $([System.IO.Path]::GetFileName($fp))"};Save-CurrentConfig}
function Open-Images{$fd=New-Object Microsoft.Win32.OpenFileDialog;$fd.Multiselect=$true;$fd.Filter="Images|*.jpg;*.jpeg;*.png;*.bmp;*.gif;*.tiff;*.tif;*.ico|All|*.*";$fd.Title="Open Image";if(-not [string]::IsNullOrEmpty($script:config.LastFolder) -and [System.IO.Directory]::Exists($script:config.LastFolder)){$fd.InitialDirectory=$script:config.LastFolder};if($fd.ShowDialog() -ne $true){return};$script:images.Clear();$script:imageCache.Clear();if($fd.FileNames.Count -eq 1){$dir=[System.IO.Path]::GetDirectoryName($fd.FileNames[0]);$script:config.LastFolder=$dir;Build-FolderTree $dir;Populate-ImagePreviews $dir;$script:currentIndex=0;for($i=0;$i -lt $script:images.Count;$i++){if($script:images[$i] -eq $fd.FileNames[0]){$script:currentIndex=$i;break}}}else{foreach($f in ($fd.FileNames|Sort-Object)){$script:images.Add($f)};$script:currentIndex=0;$dir=[System.IO.Path]::GetDirectoryName($fd.FileNames[0]);$script:config.LastFolder=$dir;Build-FolderTree $dir;$script:currentFolder=$dir;$PreviewHeader.Text="IMAGES ($($script:images.Count))";$ImagePreviewList.Items.Clear();$ct=0;foreach($f in $script:images){if($ct -ge $script:maxPreviewLoad){break};$ImagePreviewList.Items.Add((New-PreviewElement $f $script:thumbSize))|Out-Null;$ct++}};Update-Image;Save-CurrentConfig}
function Step-Next{if($script:images.Count -eq 0){return};$script:currentIndex=($script:currentIndex+1)%$script:images.Count;Update-Image}
function Step-Prev{if($script:images.Count -eq 0){return};$script:currentIndex=($script:currentIndex-1+$script:images.Count)%$script:images.Count;Update-Image}

# Save on close
$window.Add_Closing({Save-CurrentConfig})

# Events
$HamburgerBtn.Add_Click({$script:panelVisible=-not $script:panelVisible;Apply-PanelVisibility})
$OpenFolderBtn.Add_Click({Open-Folder})
$ThumbSmallerBtn.Add_Click({$ci=[Array]::IndexOf($script:thumbSizes,$script:thumbSize);if($ci -lt 0){$ci=2};if($ci -gt 0){$script:thumbSize=$script:thumbSizes[$ci-1];$ThumbSizeLabel.Text="$($script:thumbSize)";Rebuild-Previews;Save-CurrentConfig}})
$ThumbLargerBtn.Add_Click({$ci=[Array]::IndexOf($script:thumbSizes,$script:thumbSize);if($ci -lt 0){$ci=2};if($ci -lt ($script:thumbSizes.Count-1)){$script:thumbSize=$script:thumbSizes[$ci+1];$ThumbSizeLabel.Text="$($script:thumbSize)";Rebuild-Previews;Save-CurrentConfig}})
$ViewThumbBtn.Add_Click({$script:viewMode="Thumbnails";Apply-ViewMode;Rebuild-Previews;Save-CurrentConfig})
$ViewDetailBtn.Add_Click({$script:viewMode="Details";Apply-ViewMode;Rebuild-Previews;Save-CurrentConfig})
$SortNameBtn.Add_Click({if($script:sortColumn -eq "Name"){$script:sortDirection=if($script:sortDirection -eq "Ascending"){"Descending"}else{"Ascending"}}else{$script:sortColumn="Name";$script:sortDirection="Ascending"};Update-SortIndicators;Rebuild-Previews;Save-CurrentConfig})
$SortSizeBtn.Add_Click({if($script:sortColumn -eq "Size"){$script:sortDirection=if($script:sortDirection -eq "Ascending"){"Descending"}else{"Ascending"}}else{$script:sortColumn="Size";$script:sortDirection="Ascending"};Update-SortIndicators;Rebuild-Previews;Save-CurrentConfig})
$SortDateBtn.Add_Click({if($script:sortColumn -eq "Date"){$script:sortDirection=if($script:sortDirection -eq "Ascending"){"Descending"}else{"Ascending"}}else{$script:sortColumn="Date";$script:sortDirection="Descending"};Update-SortIndicators;Rebuild-Previews;Save-CurrentConfig})
$FolderTree.Add_SelectedItemChanged({param($s,$e);$sel=$e.NewValue;if($null -eq $sel){return};$fp2=$sel.Tag;if([string]::IsNullOrEmpty($fp2) -or -not [System.IO.Directory]::Exists($fp2)){return};Populate-ImagePreviews $fp2;if($script:images.Count -gt 0){$script:currentIndex=0;Update-Image}else{$PlaceholderPanel.Visibility='Visible';$MainImage.Source=$null;$FSImage.Source=$null;$FileInfoLabel.Text="";$FileCountLabel.Text="";$FileNameLabel.Text="";$window.Title="Windows Photo Viewer - $([System.IO.Path]::GetFileName($fp2))"}})
$ImagePreviewList.Add_SelectionChanged({param($s,$e);if($script:updatingSelection){return};$idx=$ImagePreviewList.SelectedIndex;if($idx -lt 0){return};if($idx -lt $ImagePreviewList.Items.Count){$item=$ImagePreviewList.Items[$idx];if($item -is [System.Windows.Controls.TextBlock] -and $item.Text -match "click to load all"){Load-MorePreviews;return}};if($idx -ge $script:images.Count){return};$script:currentIndex=$idx;Update-Image})
$PlaceholderOpenBtn.Add_Click({Open-Images});$NextBtn.Add_Click({Step-Next});$PrevBtn.Add_Click({Step-Prev});$FSNextBtn.Add_Click({Step-Next});$FSPrevBtn.Add_Click({Step-Prev})
$MenuOpen.Add_Click({Open-Images});$MenuFit.Add_Click({if($null -ne $MainImage.Source){$script:zoomMode="BestFit";Fit-ToWindow;Save-CurrentConfig}});$MenuActual.Add_Click({if($null -ne $MainImage.Source){$script:zoomMode="ActualSize";Apply-Zoom 1.0;Save-CurrentConfig}})
$script:zoomLevels=@(0.10,0.25,0.33,0.50,0.67,0.75,1.0,1.25,1.5,2.0,3.0,4.0,6.0,8.0)
$ZoomInBtn.Add_Click({if($null -eq $MainImage.Source){return};$c=$script:currentZoom;$n=$script:zoomLevels|Where-Object{$_ -gt ($c+0.005)}|Select-Object -First 1;if($null -eq $n){$n=$script:zoomLevels[-1]};Apply-Zoom $n})
$ZoomOutBtn.Add_Click({if($null -eq $MainImage.Source){return};$c=$script:currentZoom;$p=$script:zoomLevels|Where-Object{$_ -lt ($c-0.005)}|Select-Object -Last 1;if($null -eq $p){$p=$script:zoomLevels[0]};Apply-Zoom $p})
$FitBtn.Add_Click({if($null -ne $MainImage.Source){$script:zoomMode="BestFit";Fit-ToWindow;Save-CurrentConfig}})
$DeleteBtn.Add_Click({if($script:images.Count -eq 0){return};$path=$script:images[$script:currentIndex];$name=[System.IO.Path]::GetFileName($path);$r=[System.Windows.MessageBox]::Show("Move '$name' to the Recycle Bin?","Windows Photo Viewer",[System.Windows.MessageBoxButton]::YesNo,[System.Windows.MessageBoxImage]::Question);if($r -eq 'Yes'){try{[Microsoft.VisualBasic.FileIO.FileSystem]::DeleteFile($path,'OnlyErrorDialogs','SendToRecycleBin');$script:imageCache.Remove($path);$script:images.RemoveAt($script:currentIndex);$script:allFolderFiles=@($script:allFolderFiles|Where-Object{$_ -ne $path});if($ImagePreviewList.Items.Count -gt $script:currentIndex){$script:updatingSelection=$true;$ImagePreviewList.Items.RemoveAt($script:currentIndex);$script:updatingSelection=$false};if($script:currentIndex -ge $script:images.Count){$script:currentIndex=0};$PreviewHeader.Text="IMAGES ($($script:images.Count))";Update-Image}catch{[System.Windows.MessageBox]::Show("Could not delete.`n$_","Error",'OK','Error')}}})
function Enter-Fullscreen{if($script:images.Count -eq 0){return};$script:oldResizeMode=$window.ResizeMode;$Overlay.Visibility='Visible';$Overlay.Focus()|Out-Null;$window.WindowStyle='None';$window.ResizeMode='NoResize';$window.WindowState='Maximized';$script:slideshowRunning=$true;$script:lastMousePos=$null;$script:fsIdleTimer.Stop();$script:fsIdleTimer.Start();if($null -eq $script:slideshowTimer){$script:slideshowTimer=New-Object System.Windows.Threading.DispatcherTimer;$script:slideshowTimer.Interval=[TimeSpan]::FromSeconds(5);$script:slideshowTimer.Add_Tick({if($script:slideshowRunning){Step-Next}})};$script:slideshowTimer.Start()}
function Exit-Fullscreen{$Overlay.Visibility='Collapsed';$window.WindowStyle='SingleBorderWindow';$window.ResizeMode=$script:oldResizeMode;$window.WindowState='Normal';$window.Cursor=[System.Windows.Input.Cursors]::Arrow;$script:fsIdleTimer.Stop();$FSBottomBar.Visibility='Visible';$FSCountLabelBorder.Visibility='Visible';if($null -ne $script:slideshowTimer){$script:slideshowTimer.Stop()};$script:slideshowRunning=$false}
$FSBtn.Add_Click({Enter-Fullscreen});$FSExitBtn.Add_Click({Exit-Fullscreen})
$FSPauseBtn.Add_Click({$script:slideshowRunning=-not $script:slideshowRunning;if($script:slideshowRunning){$script:slideshowTimer.Start()}else{$script:slideshowTimer.Stop()}})
$Viewer.Add_PreviewMouseWheel({param($s,$e);if($null -eq $MainImage.Source){return};Apply-Zoom($script:currentZoom*($(if($e.Delta -gt 0){1.15}else{1/1.15})));$e.Handled=$true})
$Viewer.Add_PreviewMouseLeftButtonDown({param($s,$e);if($null -eq $MainImage.Source){return};if($e.ClickCount -eq 2){if($Overlay.Visibility -eq 'Visible'){Exit-Fullscreen}else{Enter-Fullscreen};return};$script:isDragging=$true;$script:dragStartPos=$e.GetPosition($Viewer);$script:dragStartHOffset=$Viewer.HorizontalOffset;$script:dragStartVOffset=$Viewer.VerticalOffset;$Viewer.Cursor=[System.Windows.Input.Cursors]::ScrollAll;$Viewer.CaptureMouse()|Out-Null;$e.Handled=$true})
$Viewer.Add_PreviewMouseMove({param($s,$e);if(-not $script:isDragging){return};$p=$e.GetPosition($Viewer);$Viewer.ScrollToHorizontalOffset($script:dragStartHOffset+($script:dragStartPos.X-$p.X));$Viewer.ScrollToVerticalOffset($script:dragStartVOffset+($script:dragStartPos.Y-$p.Y))})
$Viewer.Add_PreviewMouseLeftButtonUp({param($s,$e);if($script:isDragging){$script:isDragging=$false;$Viewer.ReleaseMouseCapture();$Viewer.Cursor=[System.Windows.Input.Cursors]::Arrow}})
